@Test public void selfClosingWithMultipleSlashes() {
    String html = "<img //class='test'/>";
    Document doc = Jsoup.parse(html);
    assertEquals("<img class=\"test\">", doc.body().html());
}

@Test public void selfClosingWithSlashBeforeEOF() {
    String html = "<img /";
    Document doc = Jsoup.parse(html);
    assertEquals("<img>", doc.body().html());
}

@Test public void selfClosingWithSlashAndSpace() {
    String html = "<img / class='test'/>";
    Document doc = Jsoup.parse(html);
    assertEquals("<img class=\"test\">", doc.body().html());
}
